import{_ as e,o as a,c as t,a4 as i}from"./chunks/framework.BIesbIg_.js";const k=JSON.parse('{"title":"Format Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/format-overview.md","filePath":"guide/format-overview.md"}'),n={name:"guide/format-overview.md"};function d(o,s,l,p,r,h){return a(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="format-overview" tabindex="-1">Format Overview <a class="header-anchor" href="#format-overview" aria-label="Permalink to &quot;Format Overview&quot;">​</a></h1><p>GCF is a line-oriented, text-based format. Each line is one semantic unit: a header, a symbol declaration, an edge reference, a group marker, or a comment.</p><h2 id="structure-at-a-glance" tabindex="-1">Structure at a glance <a class="header-anchor" href="#structure-at-a-glance" aria-label="Permalink to &quot;Structure at a glance&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=10 pack_root=a1b2c3</span></span>
<span class="line"><span>## targets</span></span>
<span class="line"><span>@0 fn pkg.AuthMiddleware 0.78 lsp_resolved</span></span>
<span class="line"><span>@1 type pkg.AuthConfig 0.71 ast_inferred</span></span>
<span class="line"><span>## related</span></span>
<span class="line"><span>@2 fn pkg.NewServer 0.54 lsp_resolved</span></span>
<span class="line"><span>@3 method pkg.Server.Start 0.48 lsp_resolved</span></span>
<span class="line"><span>## edges</span></span>
<span class="line"><span>@0&lt;@2 calls</span></span>
<span class="line"><span>@1&lt;@0 references</span></span></code></pre></div><p>Five elements. That&#39;s all there is.</p><h2 id="_1-header" tabindex="-1">1. Header <a class="header-anchor" href="#_1-header" aria-label="Permalink to &quot;1. Header&quot;">​</a></h2><p>The first line identifies the format and carries payload metadata:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=10 pack_root=a1b2c3d4</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>tool</code></td><td>Yes</td><td>Name of the producing tool</td></tr><tr><td><code>budget</code></td><td>No</td><td>Token budget requested by consumer</td></tr><tr><td><code>tokens</code></td><td>No</td><td>Actual tokens used in this payload</td></tr><tr><td><code>symbols</code></td><td>No</td><td>Number of symbols (informational)</td></tr><tr><td><code>pack_root</code></td><td>No</td><td>Content-addressed identity (hex hash). Enables delta encoding.</td></tr><tr><td><code>session</code></td><td>No</td><td><code>true</code> if session statefulness is active</td></tr><tr><td><code>delta</code></td><td>No</td><td><code>true</code> if this is a delta payload</td></tr></tbody></table><p>Fields are <code>key=value</code> pairs separated by spaces. Order doesn&#39;t matter.</p><h2 id="_2-symbol-lines-nodes" tabindex="-1">2. Symbol lines (nodes) <a class="header-anchor" href="#_2-symbol-lines-nodes" aria-label="Permalink to &quot;2. Symbol lines (nodes)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@{id} {kind} {qualified_name} {score} {provenance}</span></span></code></pre></div><p>Fields are positional. No field names, no delimiters, no quoting.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@0 fn github.com/org/repo/pkg.AuthMiddleware 0.78 lsp_resolved</span></span>
<span class="line"><span>@1 type github.com/org/repo/pkg.Config 0.65 ast_inferred</span></span>
<span class="line"><span>@2 method github.com/org/repo/pkg.Server.Start 0.54 lsp_resolved</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Position</th><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>1</td><td><code>@id</code></td><td>Zero-based integer, unique within this payload</td></tr><tr><td>2</td><td><code>kind</code></td><td>Abbreviated node type (see <a href="#kind-abbreviations">Kind Abbreviations</a>)</td></tr><tr><td>3</td><td><code>qualified_name</code></td><td>Full identifier (no whitespace)</td></tr><tr><td>4</td><td><code>score</code></td><td>Relevance score, 2 decimal places</td></tr><tr><td>5</td><td><code>provenance</code></td><td>Discovery method</td></tr></tbody></table><p><strong>Why this saves tokens:</strong> JSON repeats <code>&quot;qualified_name&quot;:</code>, <code>&quot;kind&quot;:</code>, <code>&quot;score&quot;:</code>, <code>&quot;provenance&quot;:</code>, <code>&quot;distance&quot;:</code> on every single record. GCF declares the structure once (positionally) and never repeats it.</p><h2 id="_3-edge-lines-relationships" tabindex="-1">3. Edge lines (relationships) <a class="header-anchor" href="#_3-edge-lines-relationships" aria-label="Permalink to &quot;3. Edge lines (relationships)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@{target}&lt;@{source} {edge_type}</span></span></code></pre></div><p>The <code>&lt;</code> arrow points toward the target. Read it as &quot;source flows into target.&quot;</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@0&lt;@2 calls        # @2 (NewServer) calls @0 (AuthMiddleware)</span></span>
<span class="line"><span>@1&lt;@0 references   # @0 (AuthMiddleware) references @1 (Config)</span></span>
<span class="line"><span>@3&lt;@2 calls        # @2 (NewServer) calls @3 (Server.Start)</span></span></code></pre></div><p><strong>Why this saves tokens:</strong> JSON edges look like <code>{&quot;source&quot;: &quot;github.com/org/repo/pkg.NewServer&quot;, &quot;target&quot;: &quot;github.com/org/repo/pkg.AuthMiddleware&quot;, &quot;edge_type&quot;: &quot;calls&quot;}</code>. That&#39;s ~100 tokens per edge. GCF edges are ~4 tokens each.</p><p>Optional status field for diff payloads:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@0&lt;@2 calls added     # new edge</span></span>
<span class="line"><span>@1&lt;@3 imports removed # deleted edge</span></span></code></pre></div><h2 id="_4-group-headers-sections" tabindex="-1">4. Group headers (sections) <a class="header-anchor" href="#_4-group-headers-sections" aria-label="Permalink to &quot;4. Group headers (sections)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## targets</span></span>
<span class="line"><span>## related</span></span>
<span class="line"><span>## extended</span></span>
<span class="line"><span>## edges</span></span>
<span class="line"><span>## distance_N</span></span></code></pre></div><p>Groups partition the payload into semantic sections. The group a symbol appears in encodes its distance from the query center:</p><table tabindex="0"><thead><tr><th>Group</th><th>Distance</th><th>Meaning</th></tr></thead><tbody><tr><td><code>## targets</code></td><td>0</td><td>Direct matches</td></tr><tr><td><code>## related</code></td><td>1</td><td>One hop from targets</td></tr><tr><td><code>## extended</code></td><td>2</td><td>Broader context</td></tr><tr><td><code>## distance_N</code></td><td>N</td><td>Explicit distance for N &gt; 2</td></tr><tr><td><code>## edges</code></td><td>n/a</td><td>Relationship section</td></tr></tbody></table><p><strong>Why this saves tokens:</strong> Instead of a <code>&quot;distance&quot;: 0</code> field on every record, one header replaces N fields.</p><h2 id="_5-comments" tabindex="-1">5. Comments <a class="header-anchor" href="#_5-comments" aria-label="Permalink to &quot;5. Comments&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># This is a comment (ignored by parsers)</span></span></code></pre></div><p>Lines starting with <code># </code> (hash, space) are comments.</p><h2 id="kind-abbreviations" tabindex="-1">Kind abbreviations <a class="header-anchor" href="#kind-abbreviations" aria-label="Permalink to &quot;Kind abbreviations&quot;">​</a></h2><p>GCF abbreviates common node types:</p><table tabindex="0"><thead><tr><th>Abbreviation</th><th>Full form</th></tr></thead><tbody><tr><td><code>fn</code></td><td>function</td></tr><tr><td><code>type</code></td><td>type</td></tr><tr><td><code>method</code></td><td>method</td></tr><tr><td><code>iface</code></td><td>interface</td></tr><tr><td><code>var</code></td><td>var</td></tr><tr><td><code>const</code></td><td>const</td></tr><tr><td><code>class</code></td><td>class</td></tr><tr><td><code>field</code></td><td>field</td></tr><tr><td><code>route</code></td><td>route_handler</td></tr><tr><td><code>ext</code></td><td>external</td></tr><tr><td><code>file</code></td><td>file</td></tr><tr><td><code>pkg</code></td><td>package</td></tr><tr><td><code>svc</code></td><td>service</td></tr><tr><td><code>table</code></td><td>table</td></tr><tr><td><code>resource</code></td><td>resource</td></tr><tr><td><code>selector</code></td><td>selector</td></tr></tbody></table><p>Unknown kinds are passed through verbatim (no error).</p><h2 id="comparison-the-same-data-in-json" tabindex="-1">Comparison: the same data in JSON <a class="header-anchor" href="#comparison-the-same-data-in-json" aria-label="Permalink to &quot;Comparison: the same data in JSON&quot;">​</a></h2><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;context_for_task&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tokens_used&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1847</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;token_budget&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;symbols&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;qualified_name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github.com/org/repo/pkg.AuthMiddleware&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;kind&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;function&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;score&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.78</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;provenance&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lsp_resolved&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;distance&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;qualified_name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github.com/org/repo/pkg.NewServer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;kind&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;function&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;score&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.54</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;provenance&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lsp_resolved&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;distance&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;edges&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;source&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github.com/org/repo/pkg.NewServer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;target&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github.com/org/repo/pkg.AuthMiddleware&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;edge_type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;calls&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>vs GCF:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=2</span></span>
<span class="line"><span>## targets</span></span>
<span class="line"><span>@0 fn github.com/org/repo/pkg.AuthMiddleware 0.78 lsp_resolved</span></span>
<span class="line"><span>## related</span></span>
<span class="line"><span>@1 fn github.com/org/repo/pkg.NewServer 0.54 lsp_resolved</span></span>
<span class="line"><span>## edges</span></span>
<span class="line"><span>@0&lt;@1 calls</span></span></code></pre></div><p>965 tokens vs 233 tokens. Same information.</p><h2 id="tabular-encoding-generic-profile" tabindex="-1">Tabular encoding (generic profile) <a class="header-anchor" href="#tabular-encoding-generic-profile" aria-label="Permalink to &quot;Tabular encoding (generic profile)&quot;">​</a></h2><p>The elements above (Sections 1-5) form the <strong>graph profile</strong> for code graph payloads. GCF also supports a <strong>tabular profile</strong> for encoding arbitrary structured data:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## employees [3]{id,name,department,salary}</span></span>
<span class="line"><span>1|Alice Smith|Engineering|95000</span></span>
<span class="line"><span>2|Bob Jones|Sales|72000</span></span>
<span class="line"><span>3|Carol Wu|Marketing|85000</span></span></code></pre></div><p>One header declares field names. Rows are positional values separated by pipes. No field names repeated per record. This is the same principle as the graph profile (positional fields eliminate per-record overhead), generalized to any data shape.</p><p>For nested objects: <code>key=value</code> pairs and <code>## section</code> headers. For records with sub-objects: <code>@N</code> prefixes on rows with <code>.fieldname</code> inline nested blocks.</p><p>See the <a href="/gcf/reference/spec.html">Specification (Section 6a)</a> and <a href="/gcf/reference/cheatsheet.html">Syntax Cheatsheet</a> for full details.</p><h2 id="design-constraints" tabindex="-1">Design constraints <a class="header-anchor" href="#design-constraints" aria-label="Permalink to &quot;Design constraints&quot;">​</a></h2><ul><li><strong>Text-only.</strong> No binary framing.</li><li><strong>Line-oriented.</strong> One semantic unit per line.</li><li><strong>Shallow nesting.</strong> The graph profile is flat. The tabular profile supports indented nested fields for records with sub-objects.</li><li><strong>Deterministic.</strong> Same input produces same output.</li><li><strong>Human-readable.</strong> No tooling required to understand it.</li><li><strong>LLM-parseable.</strong> Validated at 100% accuracy on structured extraction tasks.</li></ul>`,48)])])}const g=e(n,[["render",d]]);export{k as __pageData,g as default};
